'use client';

import type { Balance } from '@/types';
import { formatCurrency } from '@/lib/formatters';

interface BalanceCardProps {
  balance: Balance;
  label: string;
  flag: string;
  sublabel: string;
  change?: string;
  changePositive?: boolean;
  isPrimary?: boolean;
}

export function BalanceCard({ balance, label, flag, sublabel, change, changePositive = true, isPrimary = false }: BalanceCardProps) {
  return (
    <div className={`relative overflow-hidden rounded-2xl p-6 flex flex-col gap-4 border transition-all duration-200 hover:border-[#2e2e50] bg-[#0f0f1a] ${isPrimary ? 'border-[#2a2a45] ring-1 ring-indigo-500/20' : 'border-[#1e1e32]'}`}>
      {isPrimary && <div className="pointer-events-none absolute -top-10 -right-10 h-40 w-40 rounded-full bg-indigo-600/10 blur-2xl" />}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <span className="text-xl leading-none">{flag}</span>
          <span className="text-[11px] font-semibold tracking-widest text-zinc-500 uppercase">{label}</span>
        </div>
        <span className="text-[10px] font-mono text-zinc-600">{sublabel}</span>
      </div>
      <div>
        <p className="font-mono text-3xl font-semibold tracking-tight text-zinc-100 leading-none">
          {formatCurrency(balance.amount, balance.currency)}
        </p>
        {change && (
          <p className={`mt-2 text-xs font-medium ${changePositive ? 'text-emerald-400' : 'text-red-400'}`}>
            {changePositive ? '↑' : '↓'} {change} this month
          </p>
        )}
      </div>
    </div>
  );
}
